CREATE TABLE IF NOT EXISTS hangars (  player_id       INT NOT NULL PRIMARY KEY REFERENCES players(id) ON DELETE CASCADE,  max_ships       INT NOT NULL DEFAULT 5,  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW());CREATE TABLE IF NOT EXISTS docking_stations (  id              SERIAL PRIMARY KEY,  player_id       INT NOT NULL REFERENCES players(id) ON DELETE CASCADE,  capacity        INT NOT NULL DEFAULT 5,  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW());CREATE TABLE IF NOT EXISTS ships (  id              SERIAL PRIMARY KEY,  player_id       INT NOT NULL REFERENCES players(id) ON DELETE CASCADE,  name            TEXT NOT NULL,  galactic_id     TEXT NOT NULL UNIQUE,  rarity          TEXT NOT NULL,  stats           JSONB NOT NULL,  crew            INT[] NOT NULL DEFAULT '{}',  status          TEXT NOT NULL DEFAULT 'docked',  deleted_at      TIMESTAMPTZ,  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW());CREATE TABLE IF NOT EXISTS equipment (  id              SERIAL PRIMARY KEY,  player_id       INT NOT NULL REFERENCES players(id) ON DELETE CASCADE,  name            TEXT NOT NULL,  description     TEXT,  rarity          TEXT NOT NULL,  price           INT NOT NULL,  effect          TEXT NOT NULL,  quantity        INT NOT NULL DEFAULT 1,  assigned_to_ship INT REFERENCES ships(id) ON DELETE SET NULL,  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW());ALTER TABLE players ADD COLUMN IF NOT EXISTS next_ship_id INT NOT NULL DEFAULT 1;ALTER TABLE mission_instances   DROP COLUMN IF EXISTS recruit_id,  ADD COLUMN IF NOT EXISTS ship_id INT REFERENCES ships(id) ON DELETE SET NULL,  ADD COLUMN IF NOT EXISTS base_travel_time INT DEFAULT 3600000,  ADD COLUMN IF NOT EXISTS effective_travel_time INT;CREATE INDEX IF NOT EXISTS idx_ships_player ON ships(player_id);CREATE INDEX IF NOT EXISTS idx_equipment_player ON equipment(player_id);CREATE INDEX IF NOT EXISTS idx_docking_stations_player ON docking_stations(player_id);